/* Инструкция: Инкассация банкомата Nautilus Hyosung MoniMax S8600 */
window.INSTRUCTIONS.atm_inkass = {
  title:"Инкассация банкомата Nautilus Hyosung MoniMax S8600",
  meta:"~20 шагов · Банкоматы",
  category:"atm",
  start:"pre",
  nodes:{

    pre:{ type:"choice", question:"Что сейчас на экране банкомата?",
      options:[
        {label:"Обычный экран ожидания клиентов", next:"a1"},
        {label:"«Банкомат временно не работает»", next:"end_broken"}
      ]},

    end_broken:{ type:"end", title:"Банкомат неисправен",
      text:"Инкассацию проводить нельзя. Обратитесь в тех. поддержку банка для уточнения информации по сбою или неисправности банкомата.",
      imgs:["data:image/jpeg;base64,"] },

    a1:{ type:"step", n:1, of:20, title:"Откройте фальш-панель банкомата",
      text:`<p>Специальным ключом откройте фальш-панель банкомата, закрывающую сейфовую зону. Замок обведён красной линией на иллюстрации слева.</p>`,
      imgs:["data:image/jpeg;base64,","data:image/jpeg;base64,"],
      next:"a2" },

    a2:{ type:"step", n:2, of:20, title:"Вставьте транспортный ключ",
      text:`<p>После того как фальш-панель открылась и появился доступ к сейфовой двери, воспользуйтесь «транспортным» ключом (варианты ключей — на фото справа).</p><p>Вставьте транспортный ключ в замочную скважину, обозначенную цифрой «1», и проверните его по часовой стрелке до упора.</p>`,
      imgs:["data:image/jpeg;base64,","data:image/jpeg;base64,"],
      next:"a3" },

    a3:{ type:"step", n:3, of:20, title:"Введите транспортный код на лимбовом замке",
      text:`<p>Стандартный транспортировочный код замка — <code>50 50 50</code>. На лимбовом замке есть две риски: прямая (1) — для открытия сейфовой зоны, косая (2) — для перекодировки. Вводите код по <b>прямой</b> риске:</p>
        <p>1 — проворачиваем влево 4 раза, каждый раз останавливаясь на «50»<br>
        2 — проворачиваем вправо 3 раза, каждый раз останавливаясь на «50»<br>
        3 — проворачиваем влево 2 раза, каждый раз останавливаясь на «50»<br>
        4 — проворачиваем лимб вправо: если код введён верно, лимб провернётся на 1/4 и упрётся, открыв затвор для ручки<br>
        5 — если лимб крутится без упора — повторите с пункта 1<br>
        6 — проверните круглую ручку под лимбовым замком влево. Сейфовая дверь откроется.</p>`,
      imgs:["data:image/jpeg;base64,","data:image/jpeg;base64,"],
      danger:"Считать нужно начиная с первого подхода к цифре «50» (или другой нужной цифре), даже если она была в миллиметре от риски при первом проходе.",
      next:"a4" },

    a4:{ type:"step", n:4, of:20, title:"Выдвиньте кассетный модуль",
      text:`<p>После открытия сейфовой двери выдвиньте модуль для установки кассет на себя: прижмите ручку вниз и потяните на себя (фото слева).</p><p>Поднимите верхнюю крышку за ручку вверх (фото справа) — она зафиксируется на полозьях и не закроется сама.</p>`,
      imgs:["data:image/jpeg;base64,","data:image/jpeg;base64,"],
      next:"a5" },

    a5:{ type:"step", n:5, of:20, title:"Установите кассеты",
      text:`<p>Установите кассеты в соответствии с буквенно-цифровыми обозначениями. Образец правильной установки — на фото справа.</p>`,
      imgs:["data:image/jpeg;base64,","data:image/jpeg;base64,"],
      next:"a6" },

    a6:{ type:"step", n:6, of:20, title:"Закройте крышку модуля и задвиньте его",
      text:`<p>Одной рукой потяните зелёную ручку в сторону кассет (не отпуская её) и опустите крышку модуля. После того как крышка закрылась, отпустите фиксирующий рычаг и задвиньте модуль в сейфовую зону до щелчка.</p><p>При корректной установке банкомат издаст звуковой сигнал, а индикатор над ручкой начнёт часто моргать.</p>`,
      imgs:["data:image/jpeg;base64,"],
      note:"Дальше нужно сменить транспортировочный код лимбового замка и перекодировать транспортный ключ на боевой. Сейфовая дверь при этом должна оставаться открытой.",
      next:"a7" },

    a7:{ type:"step", n:7, of:20, title:"Перекодировка ключа на боевой — часть 1", branchTag:"Ключевой замок",
      text:`<p>Не поворачивая транспортный ключ из текущего положения, поверните ручку открытия ригелей в положение «закрыто» — металлические ригеля выдвинутся по краям сейфовой двери.</p><p>Поверните транспортный ключ против часовой стрелки до упора и извлеките его.</p><p>С задней стороны сейфовой двери любым удобным предметом (подойдёт длинная сторона перекодировочного ключа лимбового замка) нажмите на перекодировочную кнопку для ключевого замка.</p>`,
      imgs:["data:image/jpeg;base64,"],
      danger:"Используемый предмет не должен быть шире самой кнопки перекодировки — она должна прожаться в глубину корпуса замка.",
      next:"a8" },

    a8:{ type:"step", n:8, of:20, title:"Перекодировка ключа на боевой — часть 2", branchTag:"Ключевой замок",
      text:`<p>Не отпуская кнопку перекодировки, вставьте транспортный ключ в ключевой замок с внешней стороны сейфовой двери и проверните до упора — чуть дальше, чем при обычном повороте.</p><p>Извлеките ключ. Если он вышел без усилий — отпустите кнопку перекодировки. Если ключ не вытаскивается — проверните его в обратное положение и повторите нажатие кнопки.</p><p>Вставьте «боевой» ключ, проверните против часовой стрелки до упора и извлеките — если вышел без усилий, замок перекодирован.</p><p>Теперь вставьте «боевой» ключ и проверните по часовой стрелке до упора, затем поверните ручку открытия ригелей, пока они не задвинутся внутрь и ручка не упрётся.</p>`,
      imgs:["data:image/jpeg;base64,"],
      note:"Для смены боевого ключа обратно на транспортный — те же действия, но начиная с боевого ключа до нажатия кнопки перекодировки.",
      next:"a9" },

    a9:{ type:"step", n:9, of:20, title:"Введите текущий код по косой риске", branchTag:"Лимбовый замок",
      text:`<p>На открытой сейфовой двери введите текущий код (транспортный «50 50 50» или ранее установленный боевой) по <b>косой</b> риске, той же техникой: влево 4 раза до «50», вправо 3 раза до «50», влево 2 раза до «50». После выставления последней цифры — отпустите лимб, не проворачивая.</p>`,
      imgs:["data:image/jpeg;base64,"],
      note:"Транспортный код используется только при первичной загрузке или если сейф уже был переведён на транспортный код. В остальных случаях вводите тот код, который был установлен ранее.",
      next:"a10" },

    a10:{ type:"step", n:10, of:20, title:"Вставьте перекодировочный ключ", branchTag:"Лимбовый замок",
      text:`<p>С задней стороны сейфовой двери установите перекодировочный ключ («кочергу») в отверстие, обозначенное на фото слева. Ключ должен свободно войти до нужного места.</p>`,
      imgs:["data:image/jpeg;base64,","data:image/jpeg;base64,"],
      danger:"Если после нескольких попыток ключ не входит до нужного места — прекратите попытки и сообщите в тех. поддержку банка. Категорически запрещается вставлять ключ с силой или в неправильном положении — это может привести к фатальному выходу лимбового замка из строя.",
      next:"a11" },

    a11:{ type:"step", n:11, of:20, title:"Проверните ключ до щелчка", branchTag:"Лимбовый замок",
      text:`<p>Проверните перекодировочный ключ по часовой стрелке до лёгкого щелчка — примерно на 1/4 оборота.</p>`,
      imgs:["data:image/jpeg;base64,","data:image/jpeg;base64,"],
      next:"a12" },

    a12:{ type:"step", n:12, of:20, title:"Установите новый код по косой риске", branchTag:"Лимбовый замок",
      text:`<p>Нужный новый код уточните у своей тех. поддержки или по регламенту. Например, при смене транспортного кода «50 50 50» на боевой «40 60 30»:</p><p>1 — влево 4 раза до «40»<br>2 — вправо 3 раза до «60»<br>3 — влево 2 раза до «30»</p><p>После выставления последней цифры остановите лимб на нужной цифре, не проворачивая в другую сторону.</p>`,
      danger:"Отсчёт начинается с самого первого подхода к нужной цифре, даже если она была в паре миллиметров от риски. Если первая цифра кода совпадает с уже стоящей — сделайте полный оборот и начните отсчёт после первого нового подхода к этой цифре.",
      next:"a13" },

    a13:{ type:"step", n:13, of:20, title:"Верните перекодировочный ключ в исходное положение", branchTag:"Лимбовый замок",
      text:`<p>С задней стороны сейфовой двери верните перекодировочный ключ лимбового замка в исходное положение — он должен свободно выйти из скважины.</p><p>Если выходит не полностью свободно — немного доверните его в любую сторону и попробуйте снова, без усилий.</p>`,
      imgs:["data:image/jpeg;base64,","data:image/jpeg;base64,"],
      danger:"Если ключ не выходит без усилий — не вытаскивайте его силой, это может необратимо повредить лимбовый замок. Прекратите попытки и сообщите в тех. поддержку банка.",
      next:"a14" },

    a14:{ type:"step", n:14, of:20, title:"Проверьте новый код по прямой риске", branchTag:"Лимбовый замок",
      text:`<p>Введите этот же новый код лимба, но уже по <b>прямой</b> риске. При успешной перекодировке лимб откроет механизм ригелей, упёршись при повороте вправо после ввода третьей цифры кода — так же, как при обычном открытии.</p>`,
      next:"a15" },

    a15:{ type:"step", n:15, of:20, title:"Войдите в меню инкассации",
      text:`<p>Панель инкассации открывается на экране автоматически после открытия сейфовой зоны. Используя PIN-клавиатуру или сенсорный экран, введите логин и пароль.</p><p>Стандартные значения: логин <code>1234567890</code>, пароль <code>1234567890</code>. Если система их не принимает — уточните актуальные данные у тех. поддержки банка.</p>`,
      imgs:["data:image/jpeg;base64,","data:image/jpeg;base64,"],
      danger:"Количество попыток входа ограничено пятью. После пятой неверной попытки учётная запись блокируется — в этом случае нужно сразу обратиться в тех. поддержку банка.",
      next:"a16" },

    a16:{ type:"step", n:16, of:20, title:"Откройте раздел «Инкассация»",
      text:`<p>После входа откроется главное меню банкомата. Выберите пункт <code>2. Инкассация</code>.</p>`,
      imgs:["data:image/jpeg;base64,"],
      next:"a17" },

    a17:{ type:"step", n:17, of:20, title:"Запустите сеанс связи",
      text:`<p>В открывшемся подменю «Инкассация» выберите первую строку <code>1. Сеанс связи</code> и дождитесь его завершения.</p>`,
      imgs:["data:image/jpeg;base64,"],
      note:"Если сеанс связи завершился с ошибкой — это не критично, инкассацию можно продолжать без него. После успешного завершения инкассации сообщите об этой ошибке в тех. поддержку банка.",
      next:"q_period" },

    q_period:{ type:"choice", question:"У банкомата уже был открыт кассовый период до этого момента?",
      options:[
        {label:"Да, был открыт", next:"a18"},
        {label:"Нет, кассовый период закрыт", next:"a19"}
      ]},

    a18:{ type:"step", n:18, of:20, title:"Закройте текущий кассовый период",
      text:`<p>Выберите подменю <code>4. Закрытие кассового периода</code>. Банкомат выдаст чек об успешном закрытии и покажет сообщение на экране.</p>`,
      note:"Если чек не распечатался, но на экране появилось сообщение об успешной операции — это не критичная неисправность. Инкассацию можно продолжать, но по её окончании сообщите о сбое чекового принтера в тех. поддержку банка.",
      next:"a19" },

    a19:{ type:"step", n:19, of:20, title:"Проверьте наличие захваченных карт",
      text:`<p>Откройте замок верхнего кабинета банкомата тем же ключом, которым открывали фальш-панель, и потяните на себя экранный модуль — откроется доступ к лотку картоприёмника.</p><p>Если в лотке обнаружены карты клиентов — извлеките их и в подменю «Инкассация» выберите <code>5. Сброс счётчика захваченных карт</code>.</p>`,
      imgs:["data:image/jpeg;base64,","data:image/jpeg;base64,"],
      note:"Сброс счётчика захваченных карт можно выполнить в любой момент, независимо от открытия/закрытия кассового периода. После — задвиньте экранный модуль до щелчка замка. Если замок не защёлкнулся — повторите попытку; если не получается — сообщите в тех. поддержку банка.",
      next:"a20" },

    a20:{ type:"step", n:20, of:20, title:"Откройте новый кассовый период",
      text:`<p>Выберите подменю <code>2. Открытие кассового периода</code> — банкомат инициализирует кассеты и откроет меню ввода количества банкнот.</p><p>Введите корректное количество купюр в каждой кассете (PIN-клавиатура или сенсорный экран). После ввода банкомат откроет кассовый период и покажет итоговую сумму загруженных средств.</p>`,
      imgs:["data:image/jpeg;base64,"],
      note:"Сверьте показанную сумму с информацией, переданной для загрузки банкомата. Банкомат распечатает копию чека — при сбое принтера передайте информацию в кассу для получения электронной копии.",
      next:"a21" },

    a21:{ type:"step", n:21, of:20, title:"Закройте банкомат",
      text:`<p>После успешного открытия кассового периода закройте сейфовую дверь, задвиньте ригеля, закройте дверь боевым ключом, сбросьте введённый код лимбового замка (проверните против часовой стрелки) и закройте фальш-панель банкомата.</p><p>Выйдите из меню инкассации.</p>`,
      next:"end_ok" },

    end_ok:{ type:"end", title:"Инкассация завершена",
      text:"Банкомат вышел в режим ожидания клиентов и готов к работе.",
      imgs:["data:image/jpeg;base64,"] }
  }
};
